const text="Hello, my name is Nikitin Ihor\ni am a frontend developer\ni love to learn to get better...\n     ___________________________";let line=0,count=0,result="",resultBig="";const pre=document.querySelector("pre"),typeText=()=>{const e=setInterval(()=>{if(result+=text[line][count],pre.innerHTML=result+"|",++count>=text[line].length&&(count=0,line++),line==text.length)return clearInterval(e),pre.innerHTML=result,!0},70)};function menuOnClick(){document.getElementById("menu-bar").classList.toggle("change"),document.getElementById("nav2").classList.toggle("change"),document.getElementById("menu-bg").classList.toggle("change-bg")}typeText();